// reactapp/src/components/AppointmentForm.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import "./AppointmentForm.css";

const initialForm = {
  patientName: "",
  patientEmail: "",
  patientPhone: "",
  doctorId: "",
  appointmentDate: "",
  appointmentTime: "",
  reason: ""
};

export default function AppointmentForm() {
  const [form, setForm] = useState(initialForm);
  const [errors, setErrors] = useState({});
  const [serverError, setServerError] = useState("");
  const [success, setSuccess] = useState("");
  const [doctors, setDoctors] = useState([]);
  const apiBase = process.env.REACT_APP_API_URL || "http://localhost:8080";

  useEffect(() => {
    axios.get(`${apiBase}/api/doctors`)
      .then(r => setDoctors(Array.isArray(r.data) ? r.data : []))
      .catch(e => {
        console.error("fetch doctors failed", e);
        setDoctors([]);
      });
  }, [apiBase]);

  const handle = (k) => (ev) => {
    setForm(f => ({ ...f, [k]: ev.target.value }));
    setErrors(e => ({ ...e, [k]: "" }));
    setServerError("");
    setSuccess("");
  };

  function validateClient() {
    const e = {};
    if (!form.patientName || form.patientName.trim().length < 2) e.patientName = "Patient name required";
    if (!form.doctorId) e.doctorId = "Pick a doctor";
    if (!form.appointmentDate) e.appointmentDate = "Date required";
    if (!form.appointmentTime) e.appointmentTime = "Time required";
    if (!form.reason || form.reason.trim().length < 10) e.reason = "Reason required (min 10 chars)";
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  // convert UI date/time to backend-expected strings:
  function formatPayload() {
    // appointmentDate from <input type=date> already gives yyyy-mm-dd in most browsers
    // appointmentTime from <input type=time> gives HH:MM (24-hour). If your UI uses other inputs, convert here.
    return {
      patientName: form.patientName.trim(),
      patientEmail: form.patientEmail?.trim() || null,
      patientPhone: form.patientPhone?.trim() || null,
      doctorId: Number(form.doctorId),
      appointmentDate: form.appointmentDate, // must be "YYYY-MM-DD"
      appointmentTime: form.appointmentTime, // must be "HH:mm"
      reason: form.reason.trim()
    };
  }

  async function submit() {
    setServerError("");
    setSuccess("");
    if (!validateClient()) return;

    const payload = formatPayload();


    
    console.debug("Booking payload:", payload);

    try {
      const res = await axios.post(`${apiBase}/api/appointments`, payload, {
        headers: { "Content-Type": "application/json" }
      });
      setSuccess("Appointment successfully booked");
      setForm(initialForm);
    } catch (err) {
      console.error("booking error", err);
      // Use server message if present
      const msg = err?.response?.data?.message || err.message || "Network error";
      setServerError(msg);
    }
  }

  return (
    <div className="appointment-card">
      <h2 className="appointment-title">Book Appointment</h2>
      <div className="appointment-form" onKeyDown={(e)=>{ if(e.key === "Enter") e.preventDefault(); }}>
        <div className="form-group">
          <label className="field-label">Patient</label>
          <input className="field-input" value={form.patientName} onChange={handle("patientName")} placeholder="Your full name" />
          {errors.patientName && <div className="field-error">{errors.patientName}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">Doctor</label>
          <select className="field-input" value={form.doctorId} onChange={handle("doctorId")}>
            <option value="">Select doctor</option>
            {doctors.map(d => <option key={d.id} value={d.id}>{d.name} ({d.specialization})</option>)}
          </select>
          {errors.doctorId && <div className="field-error">{errors.doctorId}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">Appointment date</label>
          <input type="date" className="field-input" value={form.appointmentDate} onChange={handle("appointmentDate")} />
          {errors.appointmentDate && <div className="field-error">{errors.appointmentDate}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">Appointment time</label>
          <input type="time" className="field-input" value={form.appointmentTime} onChange={handle("appointmentTime")} />
          {errors.appointmentTime && <div className="field-error">{errors.appointmentTime}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">Reason for appointment</label>
          <textarea className="field-input textarea-field" value={form.reason} onChange={handle("reason")} />
          {errors.reason && <div className="field-error">{errors.reason}</div>}
        </div>

        {serverError && <div className="field-error">{serverError}</div>}
        {success && <div className="field-success">{success}</div>}

        <button className="primary-btn" type="button" onClick={submit}>Book Appointment</button>
      </div>
    </div>
  );
}
